output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?empire ?empireLabel ?inception ?dissolution ?capitalLabel ?founderLabel WHERE {
  VALUES ?empire {
    wd:Q2277 wd:Q12548
  }
  .
  ?empire rdfs:label ?empireLabel .
  FILTER(lang(?empireLabel) = 'en')
  OPTIONAL {
    ?empire wdt:P571 ?inception
  }
  OPTIONAL {
    ?empire wdt:P576 ?dissolution
  }
  OPTIONAL {
    ?empire wdt:P36 ?capital .
    ?capital rdfs:label ?capitalLabel .
    FILTER(lang(?capitalLabel) = 'en')
  }
  OPTIONAL {
    ?empire wdt:P112 ?founder .
    ?founder rdfs:label ?founderLabel .
    FILTER(lang(?founderLabel) = 'en')
  }
}
